function randomBetween(min, max, pct) {
    min = Number(min);
    max = Number(max);
    pct = Number(pct || 0) / 100;
    if (isNaN(min) || isNaN(max)) return 0;
    if (max < min) {
        let temp = min;
        min = max;
        max = temp;
    }
    // Base random strictly between min & max
    let base = Math.random() * (max - min) + min;
    // Apply controlled randomness
    let variation = (max - min) * pct;
    let value = base + (Math.random() * variation - variation / 2);
    // Clamp value strictly inside range
    value = Math.max(min, Math.min(max, value));
    return Number(value.toFixed(2));
}

function calculateBRWHMSFlow(hsensor, hmin, hmax, A, B) {
    hsensor = Number(hsensor || 0);
    hmin = Number(hmin || 0);
    hmax = Number(hmax || 0);
    A = Number(A || 0);
    B = Number(B || 0);
    randomnessPercent = Number(randomnessPercent || 0) / 100;
    // ✅ Step 1: Add randomness to hsensor
    let variation = (hmax - hmin) * randomnessPercent;
    let randomOffset = (Math.random() * variation) - (variation / 2);
    let randomizedHeight = hsensor + randomOffset;
    // ✅ Step 2: Clamp inside limits
    randomizedHeight = Math.max(hmin, Math.min(hmax, randomizedHeight));
    // Round height
    randomizedHeight = Number(randomizedHeight.toFixed(2));
    let Hcal = hmax - Number(randomizedHeight || 0);
    let flow = 0;
    if (Hcal <= 0) {
        flow = 0;
    }
    else if (Hcal >= hmax) {
        flow = 0;
    }
    else if (Hcal > 0 && Hcal < hmin) {
        flow = A * Math.pow(Hcal, B);
    }
    else if (Hcal >= hmin && Hcal < hmax) {
        flow = A * Math.pow(hmin, B);
    }
    return Number(flow.toFixed(2));
}

function generateGradualHeight(current, min, max, direction, pct) {
    // Step size based on range
    let range = max - min;
    let baseStep = range * (pct / 100);
    // Add slight randomness to step
    let stepVariation = baseStep * 0.3;
    let step = baseStep + (Math.random() * stepVariation);
    // Apply direction
    current += direction * step;
    // If hits max, reverse
    if (current >= max) {
        current = max;
        direction = -1;
    }
    // If hits min, reverse
    if (current <= min) {
        current = min;
        direction = 1;
    }
    return {
        height: Number(current.toFixed(2)),
        direction: direction
    };
}
function randomAround(avg, pct, minRange, maxRange) {
    avg = Number(avg || 0);
    pct = Number(pct || 0) / 100;
    minRange = Number(minRange);
    maxRange = Number(maxRange);
    // Step 1: Calculate percentage-based bounds
    let calcMin = Math.floor(avg * (1 - pct));
    let calcMax = Math.ceil(avg * (1 + pct));
    // Step 2: Apply user-defined min/max limits
    let finalMin = Math.max(calcMin, minRange);
    let finalMax = Math.min(calcMax, maxRange);
    // Safety check (if user min/max conflicts)
    if (finalMax < finalMin) {
        finalMin = minRange;
        finalMax = maxRange;
    }
    // Step 3: Generate value
    return Math.floor(Math.random() * (finalMax - finalMin + 1)) + finalMin;
}
function formatFixed(value, intDigits, decimalDigits) {
    value = Number(value || 0).toFixed(decimalDigits);
    let parts = value.split(".");
    parts[0] = parts[0].padStart(intDigits, "0");
    return parts.join(".");
}

function formatInteger(value, digits) {
